// Code pour node "Code" dans n8n
// Nettoie le markdown en supprimant les liens, URLs et texte indésirable

// Récupérer le markdown depuis l'item d'entrée
const markdown = $input.item.json.data.markdown;

// Fonction pour nettoyer le markdown
function cleanMarkdown(text) {
  if (!text) return '';

  let cleaned = text;

  // 1. Supprimer "Passer au contenu principal" et "Aller au contenu" (insensible à la casse)
  cleaned = cleaned.replace(/passer au contenu principal/gi, '');
  cleaned = cleaned.replace(/aller au contenu/gi, '');

  // 2. Convertir les liens markdown [texte](url) en texte simple
  // Garde le texte entre [], supprime les [] et (url)
  cleaned = cleaned.replace(/\[([^\]]+)\]\([^\)]+\)/g, '$1');

  // 3. Supprimer les crochets restants [] et garder leur contenu
  cleaned = cleaned.replace(/\[([^\]]+)\]/g, '$1');

  // 4. Supprimer les URLs standalone (http://, https://, www.)
  cleaned = cleaned.replace(/https?:\/\/[^\s)]+/g, '');
  cleaned = cleaned.replace(/www\.[^\s)]+/g, '');

  // 5. Supprimer les parenthèses qui contiennent des URLs résiduelles
  cleaned = cleaned.replace(/\([^)]*(?:http|www)[^)]*\)/g, '');

  // 6. Nettoyer les espaces multiples créés par les suppressions
  cleaned = cleaned.replace(/  +/g, ' ');

  // 7. Nettoyer les lignes vides multiples
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');

  // 8. Supprimer les espaces en début/fin de lignes
  cleaned = cleaned.split('\n').map(line => line.trim()).join('\n');

  // 9. Supprimer les espaces en début/fin du texte
  cleaned = cleaned.trim();

  return cleaned;
}

// Appliquer le nettoyage
const cleanedMarkdown = cleanMarkdown(markdown);

// IMPORTANT : Retourner un TABLEAU contenant l'item
// Cela préserve le "pairing" avec les items précédents
return [{
  json: {
    markdown_clean: cleanedMarkdown,
  }
}];
